mapper.select:
SELECT COUNT(*)
FROM v_dc3_point_value_all
WHERE create_time >= #{from}
  AND create_time < #{to}
  AND tenant_id = #{tenantId}

SELECT COUNT(*)
FROM v_dc3_point_value_all
WHERE tenant_id = #{tenantId}

SELECT public.time_bucket(INTERVAL '${bucket}', create_time) AS bucket,
       COUNT(*)                                              AS count
FROM v_dc3_point_value_all
WHERE create_time >= #{from}
  AND create_time < #{to}
  AND tenant_id = #{tenantId}
GROUP BY bucket
ORDER BY bucket ASC

SELECT ${dimension} AS entity_id,
       COUNT(*)     AS count
FROM v_dc3_point_value_all
WHERE create_time >= #{from}
  AND create_time < #{to}
  AND tenant_id = #{tenantId}
GROUP BY ${dimension}
ORDER BY count DESC
LIMIT #{limit}

SELECT EXTRACT(DOW FROM create_time)::int AS dow, EXTRACT(HOUR FROM create_time)::int AS hour, COUNT(*) AS count
FROM v_dc3_point_value_all
WHERE create_time >= #{from}
  AND create_time < #{to}
  AND tenant_id = #{tenantId}
GROUP BY dow, hour
ORDER BY dow ASC, hour ASC
